div.p:
c
// Build undo queue from ACTIVE transactions
for (entry in txn_table) {
if (entry.status == TXN_ACTIVE) {
UndoWorkItem item = {
.txn_id = entry.txn_id,
.record_lsn = entry.last_lsn
};
undo_queue_push(&queue, &item);  // Max-heap insert
}
}
// Process in reverse LSN order
while (!undo_queue_is_empty(&queue)) {
UndoWorkItem item = undo_queue_pop(&queue);  // Highest LSN
process_undo_item(&item);
}
